void fileiolock(struct file* f){
  switch (f->type) {
    case FD_PIPE:
        acquire(&f->pipe->lock);
        break;
    case FD_DEVICE:
        acquire(&(devsw + f->major)->lk);
        break;
    case FD_ENTRY:
        elock(f->ep);
        break;
    case FD_NONE:
    	return;
  }
}
