void
wakeup(void *chan)
{
   queue* q = findwaitq(chan);
   if(q){
     struct proc* p;
     while((p = waitq_pop(q))!=NULL){
       p->state = RUNNABLE;
       readyq_push(p);
     }
     delwaitq(q);
   }
}
```

